async function main() {
  // Configuration - replace with actual addresses
  const ROUTER_ADDRESS = "0x7a250d5630B4cF539739dF2C5dAcb4c659F2488D"; // Uniswap V2 Router
  const PROVIDER_URL = "http://127.0.0.1:8545"; // Local node or Infura/Alchemy URL

  // Example token addresses (Ethereum mainnet)
  const USDC = "0xA0b86991c6218b36c1d19D4a2e9Eb0cE3606eB48";
  const DAI = "0x6B175474E89094C44Da98b954EedeAC495271d0F";
  const WETH = "0xC02aaA39b223FE8D0A0e5C4F27eAD9083C756Cc2";

  try {
    // Initialize the DApp
    const dapp = new TokenSwapDApp(PROVIDER_URL, ROUTER_ADDRESS, {
      slippageBps: 50, // 0.5% slippage
      deadlineMinutes: 20
    });

    // For node.js environments, set a private key
    // dapp.setPrivateKey("0xYOUR_PRIVATE_KEY_HERE");

    await dapp.initialize();

    // 1. Get token information
    console.log("\n--- Token Information ---");
    const usdcInfo = await dapp.getTokenInfo(USDC);
    console.log(`USDC: ${JSON.stringify(usdcInfo, null, 2)}`);

    const daiInfo = await dapp.getTokenInfo(DAI);
    console.log(`DAI: ${JSON.stringify(daiInfo, null, 2)}`);

    // 2. Check balances
    console.log("\n--- Balances ---");
    const ethBalance = await dapp.getETHBalance();
    console.log(`ETH Balance: ${ethBalance.formatted}`);

    const usdcBalance = await dapp.getTokenBalance(USDC);
    console.log(`USDC Balance: ${usdcBalance.formatted}`);

    // 3. Check current approvals
    console.log("\n--- Current Approvals ---");
    const usdcAllowance = await dapp.getAllowance(USDC);
    console.log(`USDC Allowance: ${usdcAllowance.isUnlimited ? "Unlimited" : usdcAllowance.formatted}`);

    // 4. Get swap quote
    console.log("\n--- Swap Quote ---");
    const quote = await dapp.getSwapQuote(USDC, DAI, "100");
    console.log(`Swap 100 USDC -> ~${quote.amountOut.formatted} DAI`);
    console.log(`Minimum output: ${quote.amountOutMin.formatted} DAI`);
    console.log(`Price: 1 USDC = ${quote.pricePerTokenIn} DAI`);

    // 5. Get pair info
    console.log("\n--- Pair Info ---");
    const pairInfo = await dapp.getPairInfo(USDC, WETH);
    console.log(`USDC/WETH pair: ${pairInfo.pairAddress}`);
    console.log(`USDC reserve: ${pairInfo.reserveA.formatted}`);
    console.log(`WETH reserve: ${pairInfo.reserveB.formatted}`);

    // 6. Estimate gas
    console.log("\n--- Gas Estimation ---");
    const gasEstimate = await dapp.estimateSwapGas(USDC, DAI, "100");
    console.log(`Gas estimate: ${JSON.stringify(gasEstimate, null, 2)}`);

    // 7. Execute swap (approve + swap in one flow)
    console.log("\n--- Executing Swap ---");
    const swapResult = await dapp.swapExactTokensForTokens(USDC, DAI, "100", {
      slippageBps: 100 // 1% slippage for this specific swap
    });
    console.log(`Swap tx: ${swapResult.transactionHash}`);
    console.log(`Actual output: ${swapResult.result.amountOut?.formatted} DAI`);

    // 8. Multi-hop swap example (USDC -> WETH -> DAI)
    console.log("\n--- Multi-hop Swap ---");
    const multiHopResult = await dapp.swapWithIntermediateToken(USDC, DAI, "100", WETH);
    console.log(`Multi-hop swap tx: ${multiHopResult.transactionHash}`);

    // 9. Swap ETH for tokens
    console.log("\n--- ETH to Token Swap ---");
    const ethSwapResult = await dapp.swapExactETHForTokens(USDC, "0.1");
    console.log(`ETH->USDC swap tx: ${ethSwapResult.transactionHash}`);

    // 10. Swap tokens for ETH
    console.log("\n--- Token to ETH Swap ---");
    const tokenToEthResult = await dapp.swapExactTokensForETH(USDC, "100");
    console.log(`USDC->ETH swap tx: ${tokenToEthResult.transactionHash}`);

    // 11. Batch approve multiple tokens
    console.log("\n--- Batch Approve ---");
    const batchResult = await dapp.batchApprove([USDC, DAI]);
    console.log(`Batch approval results: ${JSON.stringify(batchResult, null, 2)}`);

    // 12. Revoke approval (security best practice when done)
    console.log("\n--- Revoke Approval ---");
    const revokeResult = await dapp.revokeApproval(USDC);
    console.log(`Revoked approval tx: ${revokeResult.transactionHash}`);

    // Cleanup
    dapp.disconnect();
  } catch (error) {
    console.error(`Error: ${error.message}`);
  }
}

// Export for module usage
module.exports = { TokenSwapDApp };

// Run if executed directly
if (require.main === module) {
  main().catch(console.error);
}